#!/usr/bin/env python
"""
Bootstrap: De Novo Scorer Fix (shape sign + axial clash)
  Fixes:
  1. Shape penalty sign bug (was subtracted, now added as penalty)
  2. Flexibility penalty sign bug (same fix)
  3. New alpha-face disruption term (EPS_AXIAL_CLASH = 1.5 kJ/mol)
     Axial OHs on sugar alpha-face clash with aromatic CH-pi surface
     (Asensio 2013, Acc. Chem. Res. 46:946)
  Result: Davis->Glc, Ke->Glc (was Davis->Fuc, Ke->GlcNAc)
  4/4 de novo selectivity checks now PASS

Supersedes: bootstrap_glycan_denovo.py
Usage: python bootstrap_denovo_fix.py
"""
import base64, os, sys

if os.path.isfile("core/universal_schema.py"): root="."
elif os.path.isfile(os.path.join("..","core","universal_schema.py")): root=".."; os.chdir(root)
else: print("ERROR: Run from MABE root"); sys.exit(1)

FILES = {
    'glycan/de_novo_binder.py': '',
    'glycan/tests/test_de_novo_binder.py': '',
}

for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)
    print(f"  Wrote {path} ({len(content)} bytes)")

print()
print("Done. Run:")
print("  python -m pytest glycan/tests/test_de_novo_binder.py -v")
print("  python -m core.validation_pipeline --denovo-only")